(window.webpackJsonp=window.webpackJsonp||[]).push([[194],{708:function(t,n,e){"use strict";e.r(n);var o=e(3),l=Object(o.a)({},(function(){var t=this,n=t.$createElement,e=t._self._c||n;return e("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[e("p",[t._v("9月27日消息，人人公司(NYSE：RENN)今日对外宣布将以8000万美元全资收购视频分享网站56网(www.56.com)，此交易将在2011年第四季度内完成。通过此次收购，56网将成为人人公司的全资子公司， 56网联合创始人兼首席执行官周娟也将加入人人公司管理层担任副总裁。这也是人人公司纽交所上市以来，首次重大战略收购。")]),t._v(" "),e("p",[t._v("56网创办于2005年，是中国领先的视频分享网站，为网民提供视频的上传、存储和分享服务。该网站上大部分的视频都是由一些草根表演者、业余视频团体或视频爱好者所原创，用户通过电脑或者各种移动设备创造和分享很多精彩的视频内容。")]),t._v(" "),e("p",[t._v("“互联网用户在社交网站上沟通和分享的需求已经不再仅仅局限于文字和图片了，用户越来越喜欢分享自己原创的视频，并且通过这些原创视频与好友进行沟通。对56网的收购可以帮助人人的用户更加方便的在社交网络上通过视频记录和分享他们的生活。” 人人公司董事长兼首席执行官陈一舟先生表示，“相对于那些以购买专业内容为主的视频网站来说，56网一直以来都在努力为用户提供高质量的原创视频分享服务，并且拥有一大批热衷于创作原创视频的用户。收购完成后，56网和人人网之间将进行深入密切的合作，可以更好地满足我们用户的需求，并进一步提高的56网和人人网用户活跃度和网站流量，同时也可以为我们的客户提供更丰富的广告形式。”")]),t._v(" "),e("p",[t._v("56网联合创始人兼首席执行官周娟表示：“我们很高兴能成为人人公司大家庭的一位成员。人人强大的用户基础以及人人在社交网络、移动互联网和社交化电子商务等方面的成功经验和丰富资源，可以给56网很多支持，帮助我们进一步加强对用户的吸引力。”")]),t._v(" "),e("p",[t._v("在此次收购中，投资银行华兴资本担任了56网的独家财务顾问。 华兴资本专注于为中国高速成长创业型企业提供各项财务顾问服务。")]),t._v(" "),e("p",[t._v("原文：http://roll.sohu.com/20110927/n320636248.shtml")])])}),[],!1,null,null,null);n.default=l.exports}}]);